            'enginePerf': '<b>Engine\x20Performance</b>\x20tracks\x20how\x20long\x20recurring\x20processing\x20takes\x20per\x20cycle.<br><b>avg</b>\x20=\x20mean\x20of\x20last\x2020\x20runs<br><b>p95</b>\x20=\x2095th\x20percentile\x20(worst\x20typical)<br><b>max</b>\x20=\x20single\x20worst\x20run<br><span\x20class=\x22apm-tip-good\x22>●\x20&lt;25ms</span>\x20=\x20smooth<br><span\x20class=\x22apm-tip-warn\x22>●\x20&lt;100ms</span>\x20=\x20noticeable<br><span\x20class=\x22apm-tip-bad\x22>●\x20&gt;100ms</span>\x20=\x20UI\x20may\x20lag',
